/* Google Fonts */
@import url('https://fonts.googleapis.com/css2?family=Montserrat:wght@400;500;600;700&family=Playfair+Display:ital,wght@1,700&display=swap');

/* -----------------------------
   Base
----------------------------- */

body,
.n8n-form-page {
    font-family: 'Montserrat', sans-serif !important;
    background: #e5ebfb !important; /* Updated background color */
    color: #0f172a !important;
}

/* -----------------------------
   Main Wrapper
----------------------------- */

.n8n-form-page > div {
    max-width: 1100px !important;
    margin: auto !important;
}

/* Remove giant default card */
.ndv-form-card,
.form-card {
    background: transparent !important;
    border: none !important;
    box-shadow: none !important;
    padding: 0 !important;
}

/* -----------------------------
   HEADER
----------------------------- */

.form-header {
    background: linear-gradient(135deg, #0f172a, #1e3a8a) !important;
    color: white !important;

    max-width: 1100px !important;
    width: calc(100% - 40px) !important;

    margin: 40px auto 50px auto !important;

    padding: 48px 40px !important;

    border-radius: 22px !important;
    border-bottom: 4px solid #2563eb !important;

    text-align: center !important;

    box-shadow:
        0 12px 30px rgba(15,23,42,.08),
        0 2px 8px rgba(15,23,42,.04) !important;
}

/* Title */

.form-header h1 {
    font-size: 0 !important;
    margin: 0 !important;
}

.form-header h1::before {
    content: "HireSense" !important;

    font-family: 'Playfair Display', serif !important;
    font-style: italic !important;
    font-weight: 700 !important;

    font-size: 58px !important;
    color: white !important;

    display: block !important;
}

/* Subtitle */

.form-header p {
    font-size: 0 !important;
    margin-top: 12px !important;
}

.form-header p::before {
    content: "A platform that evaluates resume and hunts relevant jobs.";

    color: #cbd5e1 !important;
    font-size: 14px !important;
    font-style: italic !important;
    line-height: 1.7 !important;

    display: block !important;
}

/* -----------------------------
   FORM CARD
----------------------------- */

form,
.form-body {
    background: white !important;

    max-width: 430px !important;
    width: 100% !important;

    margin: 0 auto 50px auto !important;

    padding: 24px !important;

    border: 1px solid #e2e8f0 !important;
    border-radius: 20px !important;

    box-shadow:
        0 10px 30px rgba(15,23,42,.06),
        0 2px 6px rgba(15,23,42,.03) !important;
}

/* -----------------------------
   Field Containers
----------------------------- */

.form-group,
.input-wrapper,
div[class*="field"],
div[class*="itemContainer"] {

    margin-bottom: 12px !important;
}

/* -----------------------------
   Labels
----------------------------- */

label,
.form-label {
    font-family: "Calibri", Calibri, serif !important;
    font-size: 16px !important;
    font-weight: 700 !important;
    color: #0f172a !important;
    letter-spacing: 0.3px !important;
    text-transform: none !important;
}

/* -----------------------------
   Inputs
----------------------------- */

input,
textarea,
select {

    width: 100% !important;

    padding: 10px 12px !important;

    border: 1px solid #cbd5e1 !important;
    border-radius: 10px !important;

    background: white !important;

    font-size: 13px !important;
    color: #0f172a !important;

    box-sizing: border-box !important;
}

input:focus,
textarea:focus,
select:focus {

    border-color: #2563eb !important;

    outline: none !important;

    box-shadow:
        0 0 0 4px rgba(37,99,235,.12) !important;
}

/* -----------------------------
   Upload Area
----------------------------- */

.file-upload,
div[class*="dropzone"] {

    border: 2px dashed #cbd5e1 !important;

    border-radius: 12px !important;

    padding: 18px !important;

    background: white !important;

    text-align: center !important;
}

/* -----------------------------
   Submit Button
----------------------------- */

button[type="submit"] {

    width: 100% !important;

    background: #1e3a8a !important;
    color: white !important;

    border: none !important;
    border-radius: 12px !important;

    padding: 13px 18px !important;

    font-size: 13px !important;
    font-weight: 600 !important;

    cursor: pointer !important;

    box-shadow:
        0 6px 18px rgba(30,58,138,.15) !important;
}

button[type="submit"]:hover {
    background: #0f172a !important;
}


